**Key Security Controls**:
- **TLS/HTTPS Mandatory**: All traffic encrypted, preventing credential interception
- **bcrypt Password Hashing**: Passwords stored as bcrypt hashes, not plaintext
- **Constant-Time Comparison**: Uses `subtle.ConstantTimeCompare` to prevent timing attacks
- **Rate Limiting**: Prevents brute force attacks with token bucket algorithm
- **Environment Variables**: Credentials loaded from environment, not hardcoded
- **Audit Logging**: All authentication attempts logged with IP addresses

Excellent question! For production systems with multiple users and roles, you should transition from Basic Auth to session-based or JWT-based authentication after the initial credential verification. Basic Auth requires credentials on every request, which is inefficient and increases exposure.

**PRODUCTION PATTERN**:

```go
package main

import (
	"context"
	"crypto/rand"
	"crypto/subtle"
	"crypto/tls"
	"database/sql"
	"encoding/base64"
	"encoding/hex"
	"encoding/json"
	"log"
	"net/http"
	"os"
	"strings"
	"sync"
	"time"

	"golang.org/x/crypto/bcrypt"
	"golang.org/x/time/rate"
	_ "github.com/lib/pq"
)

type User struct {
	ID           int
	Username     string
	PasswordHash []byte
	Role         string
	Active       bool
}

type Session struct {
	UserID    int
	Username  string
	Role      string
	CreatedAt time.Time
	ExpiresAt time.Time
	IPAddress string
}

type AuthService struct {
	db            *sql.DB
	sessions      map[string]*Session
	sessionsMu    sync.RWMutex
	rateLimiters  map[string]*rate.Limiter
	rateLimiterMu sync.RWMutex
}

type contextKey string

const userContextKey contextKey = "user"

func NewAuthService(db *sql.DB) *AuthService {
	return &AuthService{
		db:           db,
		sessions:     make(map[string]*Session),
		rateLimiters: make(map[string]*rate.Limiter),
	}
}

func (a *AuthService) getRateLimiter(ip string) *rate.Limiter {
	a.rateLimiterMu.Lock()
	defer a.rateLimiterMu.Unlock()

	if limiter, exists := a.rateLimiters[ip]; exists {
		return limiter
	}

	// 5 attempts per minute per IP
	limiter := rate.NewLimiter(rate.Every(12*time.Second), 5)
	a.rateLimiters[ip] = limiter
	return limiter
}

func (a *AuthService) generateSessionToken() (string, error) {
	bytes := make([]byte, 32)
	if _, err := rand.Read(bytes); err != nil {
		return "", err
	}
	return hex.EncodeToString(bytes), nil
}

func (a *AuthService) getUserByUsername(username string) (*User, error) {
	query := `SELECT id, username, password_hash, role, active 
	          FROM users WHERE username = $1`

	var user User
	err := a.db.QueryRow(query, username).Scan(
		&user.ID,
		&user.Username,
		&user.PasswordHash,
		&user.Role,
		&user.Active,
	)
	if err != nil {
		return nil, err
	}
	return &user, nil
}

func (a *AuthService) logAuthEvent(eventType, username, ip, details string) {
	query := `INSERT INTO auth_audit_log (event_type, username, ip_address, details, created_at)
	          VALUES ($1, $2, $3, $4, $5)`
	_, err := a.db.Exec(query, eventType, username, ip, details, time.Now())
	if err != nil {
		log.Printf("ERROR: Failed to log auth event: %v", err)
	}
}

func (a *AuthService) LoginHandler(w http.ResponseWriter, r *http.Request) {
	clientIP := r.RemoteAddr

	// Rate limiting per IP
	if !a.getRateLimiter(clientIP).Allow() {
		a.logAuthEvent("RATE_LIMITED", "", clientIP, "Too many attempts")
		http.Error(w, "Too many requests", http.StatusTooManyRequests)
		return
	}

	authHeader := r.Header.Get("Authorization")
	if authHeader == "" || !strings.HasPrefix(authHeader, "Basic ") {
		w.Header().Set("WWW-Authenticate", `Basic realm="Secure API"`)
		http.Error(w, "Unauthorized", http.StatusUnauthorized)
		return
	}

	payload := strings.TrimPrefix(authHeader, "Basic ")
	decoded, err := base64.StdEncoding.DecodeString(payload)
	if err != nil {
		a.logAuthEvent("INVALID_FORMAT", "", clientIP, "Invalid base64")
		http.Error(w, "Unauthorized", http.StatusUnauthorized)
		return
	}

	creds := strings.SplitN(string(decoded), ":", 2)
	if len(creds) != 2 {
		http.Error(w, "Unauthorized", http.StatusUnauthorized)
		return
	}

	username, password := creds[0], creds[1]

	// Fetch user from database
	user, err := a.getUserByUsername(username)
	if err != nil {
		// Constant-time delay to prevent user enumeration
		bcrypt.CompareHashAndPassword([]byte("$2a$12$dummy"), []byte(password))
		a.logAuthEvent("FAILED_LOGIN", username, clientIP, "User not found")
		http.Error(w, "Invalid credentials", http.StatusUnauthorized)
		return
	}

	if !user.Active {
		a.logAuthEvent("DISABLED_ACCOUNT", username, clientIP, "Account disabled")
		http.Error(w, "Account disabled", http.StatusForbidden)
		return
	}

	// Verify password using bcrypt
	if err := bcrypt.CompareHashAndPassword(user.PasswordHash, []byte(password)); err != nil {
		a.logAuthEvent("FAILED_LOGIN", username, clientIP, "Invalid password")
		http.Error(w, "Invalid credentials", http.StatusUnauthorized)
		return
	}

	// Generate secure session token
	token, err := a.generateSessionToken()
	if err != nil {
		log.Printf("ERROR: Failed to generate session token: %v", err)
		http.Error(w, "Internal error", http.StatusInternalServerError)
		return
	}

	// Create session with expiration
	session := &Session{
		UserID:    user.ID,
		Username:  user.Username,
		Role:      user.Role,
		CreatedAt: time.Now(),
		ExpiresAt: time.Now().Add(4 * time.Hour),
		IPAddress: clientIP,
	}

	a.sessionsMu.Lock()
	a.sessions[token] = session
	a.sessionsMu.Unlock()

	a.logAuthEvent("SUCCESSFUL_LOGIN", username, clientIP, "Session created")

	// Set secure session cookie
	http.SetCookie(w, &http.Cookie{
		Name:     "session_token",
		Value:    token,
		Path:     "/",
		HttpOnly: true,
		Secure:   true,
		SameSite: http.SameSiteStrictMode,
		Expires:  session.ExpiresAt,
	})

	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(map[string]interface{}{
		"message":    "Login successful",
		"expires_at": session.ExpiresAt,
	})
}

func (a *AuthService) SessionAuthMiddleware(next http.HandlerFunc) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		cookie, err := r.Cookie("session_token")
		if err != nil {
			http.Error(w, "Unauthorized", http.StatusUnauthorized)
			return
		}

		a.sessionsMu.RLock()
		session, exists := a.sessions[cookie.Value]
		a.sessionsMu.RUnlock()

		if !exists {
			http.Error(w, "Invalid session", http.StatusUnauthorized)
			return
		}

		// Check session expiration
		if time.Now().After(session.ExpiresAt) {
			a.sessionsMu.Lock()
			delete(a.sessions, cookie.Value)
			a.sessionsMu.Unlock()
			http.Error(w, "Session expired", http.StatusUnauthorized)
			return
		}

		// IP binding check (optional but recommended)
		if session.IPAddress != r.RemoteAddr {
			a.logAuthEvent("SESSION_IP_MISMATCH", session.Username, r.RemoteAddr,
				"Expected: "+session.IPAddress)
			// Depending on security requirements, you may reject or just log
		}

		// Add user to context for downstream handlers
		ctx := context.WithValue(r.Context(), userContextKey, session)
		next(w, r.WithContext(ctx))
	}
}

func (a *AuthService) RequireRole(roles ...string) func(http.HandlerFunc) http.HandlerFunc {
	return func(next http.HandlerFunc) http.HandlerFunc {
		return func(w http.ResponseWriter, r *http.Request) {
			session := r.Context().Value(userContextKey).(*Session)

			for _, role := range roles {
				if subtle.ConstantTimeCompare([]byte(session.Role), []byte(role)) == 1 {
					next(w, r)
					return
				}
			}

			a.logAuthEvent("ACCESS_DENIED", session.Username, r.RemoteAddr,
				"Required: "+strings.Join(roles, ",")+" Has: "+session.Role)
			http.Error(w, "Forbidden", http.StatusForbidden)
		}
	}
}

func (a *AuthService) LogoutHandler(w http.ResponseWriter, r *http.Request) {
	cookie, err := r.Cookie("session_token")
	if err == nil {
		a.sessionsMu.Lock()
		if session, exists := a.sessions[cookie.Value]; exists {
			a.logAuthEvent("LOGOUT", session.Username, r.RemoteAddr, "Session destroyed")
			delete(a.sessions, cookie.Value)
		}
		a.sessionsMu.Unlock()
	}

	// Clear session cookie
	http.SetCookie(w, &http.Cookie{
		Name:     "session_token",
		Value:    "",
		Path:     "/",
		HttpOnly: true,
		Secure:   true,
		SameSite: http.SameSiteStrictMode,
		MaxAge:   -1,
	})

	w.Write([]byte("Logged out"))
}

func adminDashboard(w http.ResponseWriter, r *http.Request) {
	session := r.Context().Value(userContextKey).(*Session)
	w.Write([]byte("Welcome Admin: " + session.Username))
}

func userProfile(w http.ResponseWriter, r *http.Request) {
	session := r.Context().Value(userContextKey).(*Session)
	json.NewEncoder(w).Encode(map[string]interface{}{
		"user_id":  session.UserID,
		"username": session.Username,
		"role":     session.Role,
	})
}

func main() {
	dbURL := os.Getenv("DATABASE_URL")
	if dbURL == "" {
		log.Fatal("DATABASE_URL not set")
	}

	db, err := sql.Open("postgres", dbURL)
	if err != nil {
		log.Fatalf("Database connection failed: %v", err)
	}
	defer db.Close()

	authService := NewAuthService(db)

	// Public endpoints
	http.HandleFunc("/api/login", authService.LoginHandler)
	http.HandleFunc("/api/logout", authService.LogoutHandler)

	// Protected endpoints with RBAC
	http.HandleFunc("/api/profile",
		authService.SessionAuthMiddleware(
			authService.RequireRole("user", "admin")(userProfile),
		),
	)

	http.HandleFunc("/api/admin/dashboard",
		authService.SessionAuthMiddleware(
			authService.RequireRole("admin")(adminDashboard),
		),
	)

	// TLS configuration
	tlsConfig := &tls.Config{
		MinVersion:               tls.VersionTLS12,
		CurvePreferences:         []tls.CurveID{tls.X25519, tls.CurveP256},
		PreferServerCipherSuites: true,
		CipherSuites: []uint16{
			tls.TLS_ECDHE_ECDSA_WITH_AES_256_GCM_SHA384,
			tls.TLS_ECDHE_RSA_WITH_AES_256_GCM_SHA384,
			tls.TLS_ECDHE_ECDSA_WITH_AES_128_GCM_SHA256,
			tls.TLS_ECDHE_RSA_WITH_AES_128_GCM_SHA256,
		},
	}

	server := &http.Server{
		Addr:         ":8443",
		TLSConfig:    tlsConfig,
		ReadTimeout:  15 * time.Second,
		WriteTimeout: 15 * time.Second,
		IdleTimeout:  120 * time.Second,
	}

	log.Println("Starting secure server on :8443")
	log.Fatal(server.ListenAndServeTLS("cert.pem", "key.pem"))
}
```

**Defense in Depth Layers**:

1. **Transport Layer Security**:
```go
// TLS 1.2+ with modern cipher suites only
tlsConfig := &tls.Config{
    MinVersion: tls.VersionTLS12,
    CipherSuites: []uint16{
        tls.TLS_ECDHE_ECDSA_WITH_AES_256_GCM_SHA384,
    },
}
```

2. **Session Management**:
```go
// Cryptographically secure session tokens
bytes := make([]byte, 32)
rand.Read(bytes)
token := hex.EncodeToString(bytes)  // 64-char hex string

// Secure cookie attributes
http.SetCookie(w, &http.Cookie{
    HttpOnly: true,   // No JavaScript access
    Secure:   true,   // HTTPS only
    SameSite: http.SameSiteStrictMode,  // CSRF protection
})
```

3. **Role-Based Access Control (RBAC)**:
```go
