**Why This Is Dangerous**:
- Base64 is encoding, NOT encryption - credentials are transmitted in plaintext equivalent
- Any attacker on the network can sniff and decode credentials in seconds
- No protection against replay attacks - captured credentials work indefinitely
- Hardcoded passwords in source code expose credentials in version control
- Debug mode enabled leaks stack traces and enables code execution

**SECURE VERSION**:

```python
from flask import Flask, request, Response, abort
from werkzeug.security import check_password_hash, generate_password_hash
import os
import logging
from functools import wraps

app = Flask(__name__)
app.config['SECRET_KEY'] = os.environ.get('SECRET_KEY')

# Configure secure logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

# Passwords stored as secure hashes (loaded from secure config)
USERS = {
    "admin": generate_password_hash(os.environ.get('ADMIN_PASSWORD', '')),
    "user": generate_password_hash(os.environ.get('USER_PASSWORD', ''))
}

def check_auth(username, password):
    """Verify credentials using constant-time comparison"""
    if username not in USERS:
        # Prevent timing attacks by still checking a hash
        check_password_hash(generate_password_hash('dummy'), password)
        return False
    return check_password_hash(USERS[username], password)

def requires_auth(f):
    @wraps(f)
    def decorated(*args, **kwargs):
        auth = request.authorization
        client_ip = request.environ.get('HTTP_X_FORWARDED_FOR', request.remote_addr)

        if not auth:
            logger.warning(f"Missing auth header from {client_ip}")
            return Response(
                'Authentication required', 401,
                {'WWW-Authenticate': 'Basic realm="Secure API"'}
            )

        if not check_auth(auth.username, auth.password):
            logger.warning(f"Failed login for user '{auth.username}' from {client_ip}")
            return Response('Invalid credentials', 401)

        logger.info(f"Successful auth for '{auth.username}' from {client_ip}")
        return f(*args, **kwargs)
    return decorated

@app.route('/api/data')
@requires_auth
def get_data():
    return {"message": "Hello", "data": "sensitive info"}

if __name__ == '__main__':
    # MUST be deployed behind TLS-terminating reverse proxy
    # or use ssl_context for direct HTTPS
    ssl_context = (
        os.environ.get('SSL_CERT_PATH', 'cert.pem'),
        os.environ.get('SSL_KEY_PATH', 'key.pem')
    )
    app.run(host='0.0.0.0', port=5000, ssl_context=ssl_context, debug=False)
```

**Key Security Controls**:
- **HTTPS/TLS**: Encrypts all traffic including credentials in transit
- **Password hashing**: Uses werkzeug's secure password hashing with salt
- **Constant-time comparison**: Prevents timing attacks on authentication
- **Environment variables**: Credentials never stored in source code
- **Audit logging**: All authentication attempts logged with IP addresses

Session cookies are critical for authentication, but improper configuration makes them vulnerable to XSS-based cookie theft. The 2023 Reddit incident showed how attackers can steal session tokens through injected JavaScript, compromising thousands of accounts.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const session = require('express-session');

const app = express();

// VULNERABLE: Insecure session configuration
app.use(session({
  secret: 'mysecret123',
  resave: false,
  saveUninitialized: true,
  cookie: {
    // NO httpOnly flag - JavaScript can access cookies
    // NO secure flag - cookies sent over HTTP
    // NO sameSite - vulnerable to CSRF
    maxAge: 86400000 // 24 hours
  }
}));

app.post('/login', (req, res) => {
  const { username, password } = req.body;
  // Assuming authentication succeeds
  req.session.userId = username;
  req.session.isAuthenticated = true;
  res.send('Logged in successfully');
});

// VULNERABLE: Renders user input without sanitization
app.get('/profile', (req, res) => {
  const username = req.query.name;
  // XSS vulnerability - user input directly rendered
  res.send(`<html><body><h1>Welcome, ${username}</h1></body></html>`);
});

app.listen(3000);
