  contentSecurityPolicy: {
    directives: {
      defaultSrc: ["'self'"],
      scriptSrc: ["'self'"],
      styleSrc: ["'self'"],
      imgSrc: ["'self'", "data:", "https:"],
      connectSrc: ["'self'"],
      frameSrc: ["'none'"],
      objectSrc: ["'none'"],
      baseUri: ["'self'"],
      formAction: ["'self'"]
    }
  },
  hsts: {
    maxAge: 31536000,
    includeSubDomains: true,
    preload: true
  }
}));

// Rate limiting for authentication endpoints
const authLimiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 5, // 5 attempts per window
  message: { error: 'Too many authentication attempts' },
  standardHeaders: true,
  legacyHeaders: false,
  handler: (req, res) => {
    logger.warn('Rate limit exceeded', {
      ip: req.ip,
      path: req.path,
      userAgent: req.get('User-Agent')
    });
    res.status(429).json({ error: 'Too many requests' });
  }
});

// Redis session store configuration
const redisStore = new RedisStore({
  client: redisClient,
  prefix: 'sess:',
  ttl: 3600 // 1 hour TTL for sessions
});

// Production session configuration
app.use(session({
  store: redisStore,
  secret: process.env.SESSION_SECRET,
  name: '__Host-sid',
  resave: false,
  saveUninitialized: false,
  rolling: true, // Reset expiration on each request
  cookie: {
    httpOnly: true,
    secure: true,
    sameSite: 'strict',
    maxAge: 3600000, // 1 hour
    path: '/',
    domain: process.env.COOKIE_DOMAIN
  },
  genid: () => crypto.randomBytes(32).toString('hex') // Cryptographically secure session IDs
}));

// Session validation middleware
const validateSession = async (req, res, next) => {
  if (!req.session || !req.session.userId) {
    return res.status(401).json({ error: 'Authentication required' });
  }

  // Check if session was invalidated (e.g., password change)
  const invalidated = await redisClient.get(`invalidated:${req.session.userId}`);
  if (invalidated && new Date(req.session.createdAt) < new Date(invalidated)) {
    req.session.destroy((err) => {
      logger.info('Invalidated session destroyed', { userId: req.session.userId });
    });
    return res.status(401).json({ error: 'Session invalidated, please login again' });
  }

  // Bind session to user agent and IP for additional security
  const fingerprint = crypto
    .createHash('sha256')
    .update(`${req.ip}${req.get('User-Agent')}`)
    .digest('hex');

  if (req.session.fingerprint && req.session.fingerprint !== fingerprint) {
    logger.warn('Session fingerprint mismatch - possible hijacking attempt', {
      userId: req.session.userId,
      expectedFingerprint: req.session.fingerprint,
      actualFingerprint: fingerprint,
      ip: req.ip
    });
    req.session.destroy();
    return res.status(401).json({ error: 'Session invalid' });
  }

  next();
};

