import javax.servlet.*;
import javax.servlet.http.*;
import java.io.IOException;
import java.security.MessageDigest;
import java.util.Base64;
import java.util.logging.Logger;

public class SecureBasicAuthFilter implements Filter {

    private static final Logger logger = Logger.getLogger(SecureBasicAuthFilter.class.getName());
    private UserService userService;
    private RateLimiter rateLimiter;

    @Override
    public void init(FilterConfig filterConfig) throws ServletException {
        this.userService = new UserService();
        this.rateLimiter = new RateLimiter(5, 60000); // 5 attempts per minute
    }

    @Override
    public void doFilter(ServletRequest request, ServletResponse response, 
                         FilterChain chain) throws IOException, ServletException {

        HttpServletRequest httpRequest = (HttpServletRequest) request;
        HttpServletResponse httpResponse = (HttpServletResponse) response;

        // SECURITY: Enforce HTTPS in production
        if (!httpRequest.isSecure()) {
            logger.warning("Blocked non-HTTPS authentication attempt from: " + 
                          httpRequest.getRemoteAddr());
            httpResponse.sendError(HttpServletResponse.SC_FORBIDDEN, 
                                  "HTTPS required for authentication");
            return;
        }

        String clientIP = httpRequest.getRemoteAddr();

        // SECURITY: Rate limiting to prevent brute force
        if (!rateLimiter.allowRequest(clientIP)) {
            logger.warning("Rate limit exceeded for IP: " + clientIP);
            httpResponse.setHeader("Retry-After", "60");
            httpResponse.sendError(429, "Too Many Requests");
            return;
        }

        String authHeader = httpRequest.getHeader("Authorization");

        if (authHeader != null && authHeader.startsWith("Basic ")) {
            try {
                String base64Credentials = authHeader.substring(6);
                String credentials = new String(Base64.getDecoder().decode(base64Credentials));
                int colonIndex = credentials.indexOf(':');

                if (colonIndex > 0) {
                    String username = credentials.substring(0, colonIndex);
                    String password = credentials.substring(colonIndex + 1);

                    // SECURITY: Validate against securely stored credentials
                    if (userService.validateCredentials(username, password)) {
                        logger.info("Successful authentication for user: " + username);
                        httpRequest.setAttribute("authenticated_user", username);
                        chain.doFilter(request, response);
                        return;
                    }
                }
            } catch (IllegalArgumentException e) {
                logger.warning("Invalid Base64 in auth header from: " + clientIP);
            }
        }

        logger.warning("Failed authentication attempt from: " + clientIP);
        httpResponse.setHeader("WWW-Authenticate", "Basic realm=\"Secure API\"");
        httpResponse.sendError(HttpServletResponse.SC_UNAUTHORIZED);
    }

    @Override
    public void destroy() {}
}
```

**Key Security Controls**:
- **HTTPS enforcement**: Credentials are encrypted in transit via TLS, preventing MITM interception
- **Rate limiting**: Prevents brute force attacks by limiting authentication attempts per IP
- **Secure credential storage**: Passwords validated against hashed versions stored in database, not hardcoded
- **Constant-time comparison**: UserService uses timing-safe comparison to prevent timing attacks
- **Comprehensive logging**: All authentication events logged for security monitoring and incident response

Multi-method authentication requires a chain-of-responsibility pattern with proper security controls for each method. Each authentication type has different threat models and requires specific protections.

**PRODUCTION PATTERN**:

```java
import javax.servlet.*;
import javax.servlet.http.*;
import java.io.IOException;
import java.security.MessageDigest;
import java.security.SecureRandom;
import java.time.Instant;
import java.util.Base64;
import java.util.concurrent.ConcurrentHashMap;
import java.util.logging.Logger;
import io.jsonwebtoken.*;
import io.jsonwebtoken.security.Keys;
import javax.crypto.SecretKey;

public class MultiMethodAuthFilter implements Filter {

    private static final Logger logger = Logger.getLogger(MultiMethodAuthFilter.class.getName());
    private static final Logger auditLogger = Logger.getLogger("SECURITY_AUDIT");

    private final AuthenticationChain authChain;
    private final RateLimiterService rateLimiter;
    private final SecurityMetrics metrics;

    public MultiMethodAuthFilter() {
        this.rateLimiter = new RateLimiterService();
        this.metrics = new SecurityMetrics();

        // Build authentication chain in priority order
        this.authChain = new AuthenticationChain()
            .addAuthenticator(new JWTAuthenticator())
            .addAuthenticator(new ApiKeyAuthenticator())
            .addAuthenticator(new BasicAuthAuthenticator());
    }

    @Override
    public void init(FilterConfig filterConfig) throws ServletException {
        String env = System.getenv("APP_ENV");
        if ("production".equals(env)) {
            // Production-specific security settings
            rateLimiter.setStrictMode(true);
        }
    }

    @Override
    public void doFilter(ServletRequest request, ServletResponse response, 
                         FilterChain chain) throws IOException, ServletException {

        HttpServletRequest httpRequest = (HttpServletRequest) request;
        HttpServletResponse httpResponse = (HttpServletResponse) response;

        String clientIP = getClientIP(httpRequest);
        String requestId = generateRequestId();

        // Set security headers
        setSecurityHeaders(httpResponse);

        // HTTPS enforcement
        if (!httpRequest.isSecure() && isProductionEnv()) {
            auditLogger.warning(String.format(
                "[%s] BLOCKED: Non-HTTPS auth attempt from %s", requestId, clientIP));
            httpResponse.sendError(HttpServletResponse.SC_FORBIDDEN, 
                                  "Secure connection required");
            return;
        }

        // Global rate limiting
        RateLimitResult rateLimitResult = rateLimiter.checkLimit(clientIP);
        if (!rateLimitResult.isAllowed()) {
            metrics.incrementRateLimitBlocks();
            auditLogger.warning(String.format(
                "[%s] RATE_LIMITED: IP %s exceeded %d requests", 
                requestId, clientIP, rateLimitResult.getLimit()));

            httpResponse.setHeader("X-RateLimit-Limit", 
                                  String.valueOf(rateLimitResult.getLimit()));
            httpResponse.setHeader("X-RateLimit-Remaining", "0");
            httpResponse.setHeader("X-RateLimit-Reset", 
                                  String.valueOf(rateLimitResult.getResetTime()));
            httpResponse.setHeader("Retry-After", 
                                  String.valueOf(rateLimitResult.getRetryAfter()));
            httpResponse.sendError(429, "Rate limit exceeded");
            return;
        }

        // Attempt authentication through the chain
        AuthenticationResult authResult = authChain.authenticate(httpRequest);

        if (authResult.isAuthenticated()) {
            metrics.incrementSuccessfulAuth(authResult.getMethod());
            auditLogger.info(String.format(
                "[%s] AUTH_SUCCESS: user=%s method=%s ip=%s",
                requestId, authResult.getPrincipal(), 
                authResult.getMethod(), clientIP));

            // Set authentication context
            SecurityContext ctx = new SecurityContext(
                authResult.getPrincipal(),
                authResult.getRoles(),
                authResult.getMethod(),
                requestId
            );
            httpRequest.setAttribute("security_context", ctx);

            chain.doFilter(request, response);
        } else {
            metrics.incrementFailedAuth();
            auditLogger.warning(String.format(
                "[%s] AUTH_FAILED: reason=%s ip=%s user_agent=%s",
                requestId, authResult.getFailureReason(), 
                clientIP, httpRequest.getHeader("User-Agent")));

            // Return appropriate challenge based on supported methods
            httpResponse.setHeader("WWW-Authenticate", 
                "Bearer realm=\"api\", Basic realm=\"api\"");
            httpResponse.sendError(HttpServletResponse.SC_UNAUTHORIZED,
                                  "Authentication required");
        }
    }

    private void setSecurityHeaders(HttpServletResponse response) {
        response.setHeader("X-Content-Type-Options", "nosniff");
        response.setHeader("X-Frame-Options", "DENY");
        response.setHeader("Cache-Control", "no-store, no-cache, must-revalidate");
        response.setHeader("Pragma", "no-cache");
    }

    private String getClientIP(HttpServletRequest request) {
        String xForwardedFor = request.getHeader("X-Forwarded-For");
        if (xForwardedFor != null && !xForwardedFor.isEmpty()) {
            // Take first IP if behind trusted proxy
            return xForwardedFor.split(",")[0].trim();
        }
        return request.getRemoteAddr();
    }

    private String generateRequestId() {
        byte[] bytes = new byte[16];
        new SecureRandom().nextBytes(bytes);
        return Base64.getUrlEncoder().withoutPadding().encodeToString(bytes);
    }

    private boolean isProductionEnv() {
        return "production".equals(System.getenv("APP_ENV"));
    }

    @Override
    public void destroy() {
        metrics.shutdown();
    }
}

// JWT Authenticator with proper validation
class JWTAuthenticator implements Authenticator {

    private static final Logger logger = Logger.getLogger(JWTAuthenticator.class.getName());
    private final SecretKey secretKey;
    private final JwtParser jwtParser;

    public JWTAuthenticator() {
        // Load key from secure configuration (HSM, Vault, etc.)
        String keyBase64 = System.getenv("JWT_SECRET_KEY");
        this.secretKey = Keys.hmacShaKeyFor(Base64.getDecoder().decode(keyBase64));
        this.jwtParser = Jwts.parserBuilder()
            .setSigningKey(secretKey)
            .requireIssuer("myapp")
            .requireAudience("api")
            .build();
    }

    @Override
    public AuthenticationResult authenticate(HttpServletRequest request) {
        String authHeader = request.getHeader("Authorization");

        if (authHeader == null || !authHeader.startsWith("Bearer ")) {
            return AuthenticationResult.notApplicable();
        }

        String token = authHeader.substring(7);

        try {
            Claims claims = jwtParser.parseClaimsJws(token).getBody();

            // Validate expiration
            if (claims.getExpiration().before(new java.util.Date())) {
                return AuthenticationResult.failure("Token expired");
            }

            // Extract and validate subject
            String subject = claims.getSubject();
            if (subject == null || subject.isEmpty()) {
                return AuthenticationResult.failure("Invalid token subject");
            }

            @SuppressWarnings("unchecked")
            java.util.List<String> roles = claims.get("roles", java.util.List.class);

            return AuthenticationResult.success(subject, roles, "JWT");

        } catch (ExpiredJwtException e) {
            return AuthenticationResult.failure("Token expired");
        } catch (JwtException e) {
            logger.warning("JWT validation failed: " + e.getMessage());
            return AuthenticationResult.failure("Invalid token");
        }
    }
}

// API Key Authenticator with secure storage lookup
class ApiKeyAuthenticator implements Authenticator {

    private final ApiKeyService apiKeyService;

    public ApiKeyAuthenticator() {
        this.apiKeyService = new ApiKeyService();
    }

    @Override
    public AuthenticationResult authenticate(HttpServletRequest request) {
        String apiKey = request.getHeader("X-API-Key");

        if (apiKey == null || apiKey.isEmpty()) {
            return AuthenticationResult.notApplicable();
        }

        // Validate API key format before database lookup
        if (!isValidApiKeyFormat(apiKey)) {
            return AuthenticationResult.failure("Invalid API key format");
        }

        // Lookup API key using timing-safe comparison
        ApiKeyEntity entity = apiKeyService.findByKeyHash(hashApiKey(apiKey));

        if (entity == null) {
            return AuthenticationResult.failure("Invalid API key");
        }

        if (entity.isExpired()) {
            return AuthenticationResult.failure("API key expired");
        }

        if (entity.isRevoked()) {
            return AuthenticationResult.failure("API key revoked");
        }

        // Update last used timestamp asynchronously
        apiKeyService.updateLastUsedAsync(entity.getId());

        return AuthenticationResult.success(
            entity.getOwner(), 
            entity.getScopes(), 
            "API_KEY"
        );
    }

    private boolean isValidApiKeyFormat(String apiKey) {
        // Expected format: 32 character hex string
        return apiKey.matches("^[a-fA-F0-9]{32}$");
    }

    private String hashApiKey(String apiKey) {
        try {
            MessageDigest digest = MessageDigest.getInstance("SHA-256");
            byte[] hash = digest.digest(apiKey.getBytes(java.nio.charset.StandardCharsets.UTF_8));
            StringBuilder hexString = new StringBuilder();
            for (byte b : hash) {
                String hex = Integer.toHexString(0xff & b);
                if (hex.length() == 1) hexString.append('0');
                hexString.append(hex);
            }
            return hexString.toString();
        } catch (java.security.NoSuchAlgorithmException e) {
            throw new RuntimeException("SHA-256 not available", e);
        }
    }
}
