3. **Distributed Rate Limiting with Redis**:
```java
import redis.clients.jedis.JedisPool;

public class DistributedRateLimiter {
    private final JedisPool jedisPool;
    private final int maxRequests;
    private final int windowSeconds;

    public DistributedRateLimiter(JedisPool pool, int maxRequests, int windowSeconds) {
        this.jedisPool = pool;
        this.maxRequests = maxRequests;
        this.windowSeconds = windowSeconds;
    }

    public RateLimitResult checkLimit(String identifier) {
        String key = "ratelimit:auth:" + identifier;

        try (var jedis = jedisPool.getResource()) {
            long currentCount = jedis.incr(key);

            if (currentCount == 1) {
                jedis.expire(key, windowSeconds);
            }

            long ttl = jedis.ttl(key);

            return new RateLimitResult(
                currentCount <= maxRequests,
                maxRequests,
                maxRequests - (int) currentCount,
                Instant.now().plusSeconds(ttl).getEpochSecond(),
                (int) ttl
            );
        }
    }
}
