package main

import (
	"crypto/rand"
	"encoding/hex"
	"html/template"
	"log"
	"net/http"
	"time"
)

func main() {
	http.HandleFunc("/login", secureLoginHandler)
	http.HandleFunc("/profile", secureProfileHandler)
	http.HandleFunc("/search", secureSearchHandler)
	http.ListenAndServe(":8080", nil)
}

func secureLoginHandler(w http.ResponseWriter, r *http.Request) {
	if r.Method == "POST" {
		username := r.FormValue("username")
		password := r.FormValue("password")

		if authenticateUser(username, password) {
			// SECURE: Cookie with all security flags
			cookie := &http.Cookie{
				Name:     "session_id",
				Value:    generateSecureSessionID(),
				Expires:  time.Now().Add(24 * time.Hour),
				Path:     "/",
				HttpOnly: true,                    // Prevents JavaScript access
				Secure:   true,                    // HTTPS only
				SameSite: http.SameSiteStrictMode, // Prevents CSRF
			}
			http.SetCookie(w, cookie)
			http.Redirect(w, r, "/profile", http.StatusFound)
			return
		}
	}

	// Use template for safe HTML rendering
	tmpl := template.Must(template.New("login").Parse(`
		<html><body>
			<form method="POST">
				<input name="username">
				<input name="password" type="password">
				<button>Login</button>
