		</body></html>
	`))
	tmpl.Execute(w, nil)
}

func secureSearchHandler(w http.ResponseWriter, r *http.Request) {
	query := r.URL.Query().Get("q")

	// SECURE: Use html/template for automatic escaping
	tmpl := template.Must(template.New("search").Parse(`
		<html><body>
			<h1>Search Results for: {{.Query}}</h1>
		</body></html>
	`))

	data := struct {
		Query string
	}{
		Query: query, // Template automatically escapes this
	}

	tmpl.Execute(w, data)
}

func secureProfileHandler(w http.ResponseWriter, r *http.Request) {
	_, err := r.Cookie("session_id")
	if err != nil {
		http.Redirect(w, r, "/login", http.StatusFound)
		return
	}
	// Don't expose session ID in response
	w.Write([]byte("Welcome back!"))
}

func generateSecureSessionID() string {
	bytes := make([]byte, 32)
	if _, err := rand.Read(bytes); err != nil {
		log.Fatal(err)
	}
	return hex.EncodeToString(bytes)
}
```

**Key Security Controls**:
- **HttpOnly flag**: Prevents JavaScript from accessing the cookie, blocking XSS-based cookie theft
- **Secure flag**: Ensures cookie is only transmitted over HTTPS, preventing MITM interception
- **SameSite=Strict**: Cookie not sent with cross-origin requests, mitigating CSRF attacks
- **html/template**: Go's template package automatically escapes HTML special characters, preventing XSS
- **Cryptographically secure session IDs**: Uses crypto/rand instead of predictable values

